INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-01999', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '操作靜態視網膜檢影鏡檢查（static retinoscopy），以平行光發現患者瞳孔出現檢影鏡反射光呈剪刀狀移 動（scissors motion）現象，最常見於何種狀況？', '["年輕人的近視眼", "老年人的遠視眼", "小瞳孔", "正視眼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02000', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '執行傑克森交叉圓柱鏡檢查（Jackson cross-cylinder）時，下列何者最不適當？', '["執行散光軸度檢查時，如果被檢者表示兩種狀況下清楚的程度一樣，則可以進行下一步", "檢查散光軸度時，被檢者在兩個很小的軸度之間反覆，可以選擇這兩個軸度之間的中間軸度，以進行 下一步", "檢查散光軸度時，被檢者在兩個很小的軸度之間反覆，可以在兩個軸度中選擇比較接近原來常戴的眼 鏡的軸度，以進行下一步", "除非散光度數很大，通常會先檢查散光度數，之後才是散光軸度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02001', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者25歲，視網膜檢影鏡檢查之後，使用球面鏡片無法達到20/20 的視力，下列敘述何者錯誤？', '["可能有散光", "可以考慮使用散光圖形檢查法（clock chart, sunburst dial, astigmatic dial）", "使用散光圖形檢查法時，如果各個方向的線是一樣模糊，那麼表示沒有未矯正的散光", "操作散光圖形檢查法時，因為不採用霧視，故需維持等效球鏡度（spherical equivalent）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02002', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者35歲，透過視網膜檢影鏡、綜合驗光儀（phoropter）、交叉圓柱鏡等測得矯正度數，下列敘述何 者錯誤？', '["再次利用紅綠色標測試來檢測，來確定目前的最佳視力是由最大的正球面鏡度數（或者最小的負球面 鏡度數）所提供", "如果受檢者因為黃斑部病變等導致兩眼之間的最佳矯正視力不同，一般不需要雙眼平衡檢查（binocular balance）", "一般雙眼平衡檢查應該要一次執行一眼，因此要遮住沒有檢查的另外一眼", "一般雙眼平衡檢查可以利用3Δ到4Δ的稜鏡分別放在病人的右眼（基底朝上）與左眼（基底朝下）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02003', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '自覺式驗光中的紅綠色標測試是利用那一種原理？', '["球面像差", "色像差", "彗星像差", "斜散像差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02004', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以時鐘刻度表（clock dial test）或輻射散光圖表（radial line test）檢查時，受檢者表示 8 點鐘的線條最清 楚，其負散光的軸度最可能為下列何者？', '["030", "150", "060", "120"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02005', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '某患者驗光處方為-3.00DS/-5.00DC×090，但配戴後不適，應選擇下列那種處方最為合理？', '["-3.50DS/-4.50DC×090", "-4.00DS/-3.50DC×090", "-4.00DS/-3.00DC×090", "-4.50DS/-2.50DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02006', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關雙眼平衡的敘述，下列何者錯誤？', '["雙眼平衡的目的在使雙眼在觀看任何距離時，調節刺激均保持一致", "當單眼各自完成自覺式驗光時，若此時兩眼的矯正度數一致且最佳視力一致，則無需執行雙眼平衡", "雙眼平衡是為了達到清晰、舒適的用眼，並避免視覺疲勞", "稜鏡分離式紅綠色標測試（prism-dissociated duochrome test）可用來執行雙眼平衡測驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02007', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列何者與針孔板可以提升視力的因素無關？', '["減少入眼光線的散射現象（scattering）", "減少視網膜上的模糊現象（retinal blur）", "使焦點深度（depth of focus）變長", "降低視網膜上的照度（illumination）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02008', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '利用紅綠色標測試確認患者矯正情形時，若患者主述綠色背景裡的數字比紅色背景裡的數字較黑、較清 楚，下列處置何者正確？', '["不論是近視或遠視均增加負度數", "不論是近視或遠視均增加正度數", "遠視往負度數增加、近視往正度數增加", "遠視往正度數增加、近視往負度數增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b0d4df903d3b", "answer_pdf_sha1": "61ff00462a6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
